import{_ as l,o as r,c as a,a2 as i}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"实物奖品","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"rewards/rewards-mall/physical-prizes.md","filePath":"zh-CN/rewards/rewards-mall/physical-prizes.md"}'),d={name:"rewards/rewards-mall/physical-prizes.md"};function e(o,t,h,n,p,s){return r(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="实物奖品" tabindex="-1">实物奖品 <a class="header-anchor" href="#实物奖品" aria-label="Permalink to &quot;实物奖品&quot;">​</a></h1><p>实物商品、电子券、My Link 积分和卡密的领取、激活及使用规则。</p><h2 id="奖品类型" tabindex="-1">奖品类型 <a class="header-anchor" href="#奖品类型" aria-label="Permalink to &quot;奖品类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>奖品类型</th><th>说明</th><th>领取方式</th></tr></thead><tbody><tr><td>实物商品</td><td>有形货物，需通过快递送达</td><td>填写收货地址，等待快递</td></tr><tr><td>电子券</td><td>数字凭证，在指定商户消费时出示</td><td>APP 内激活后使用</td></tr><tr><td>My Link 积分</td><td>可在 My Link 平台使用的积分</td><td>锁仓期结束后自动到账</td></tr><tr><td>卡密</td><td>可在第三方平台兑换的密钥</td><td>APP 内点击「领取」获取密钥</td></tr></tbody></table><h2 id="如何领取实物奖品" tabindex="-1">如何领取实物奖品 <a class="header-anchor" href="#如何领取实物奖品" aria-label="Permalink to &quot;如何领取实物奖品&quot;">​</a></h2><ol><li>活动结束后，在 APP「奖励中心」或活动页面查看获奖信息</li><li>点击对应奖品，进入奖品详情页</li><li>根据奖品类型，按提示完成相应操作（填写地址 / 激活 / 领取卡密等）</li><li>在奖品详情页随时查看当前状态</li></ol><h2 id="奖品状态说明" tabindex="-1">奖品状态说明 <a class="header-anchor" href="#奖品状态说明" aria-label="Permalink to &quot;奖品状态说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>您看到的信息</th><th>需要做什么</th></tr></thead><tbody><tr><td>待填写地址</td><td>请填写收货地址</td><td>立即填写收货地址，否则无法发货</td></tr><tr><td>地址已填写</td><td>地址已提交，等待仓库处理</td><td>无需操作，等待仓库安排发货</td></tr><tr><td>发货中</td><td>已发货，物流单号：XXXX</td><td>使用物流单号在对应快递官网追踪包裹</td></tr><tr><td>已收货</td><td>奖品已送达</td><td>确认收货，如有问题请联系客服</td></tr><tr><td>电子券激活中</td><td>正在激活电子券</td><td>等待，通常 1-2 分钟内完成，无需操作</td></tr><tr><td>电子券已激活</td><td>电子券可使用</td><td>在指定商户消费时出示电子券</td></tr><tr><td>电子券已消费</td><td>电子券已在商户核销使用</td><td>无需操作，消费完成</td></tr><tr><td>电子券已过期</td><td>电子券已失效</td><td>联系客服说明情况</td></tr><tr><td>已退回</td><td>奖品因地址问题退回</td><td>联系客服，重新提供正确地址</td></tr><tr><td>拒绝发货</td><td>仓库拒绝发货（地址异常或库存问题）</td><td>联系客服说明情况，附上奖品截图</td></tr></tbody></table><h2 id="各类奖品操作指南" tabindex="-1">各类奖品操作指南 <a class="header-anchor" href="#各类奖品操作指南" aria-label="Permalink to &quot;各类奖品操作指南&quot;">​</a></h2><h3 id="实物商品-邮寄" tabindex="-1">实物商品（邮寄） <a class="header-anchor" href="#实物商品-邮寄" aria-label="Permalink to &quot;实物商品（邮寄）&quot;">​</a></h3><p>领取步骤：</p><ol><li>收到中奖通知后，进入奖品详情页</li><li>点击「填写收货地址」，填写收件人姓名、手机号码、详细地址、邮政编码</li><li>确认提交后，状态变为「地址已填写」</li><li>仓库处理后开始发货，您将收到物流单号</li></ol><p>注意事项：</p><ul><li>实物商品设有领取截止时间，必须在截止时间前填写收货地址，超过截止时间未填写地址，奖品将自动失效且无法补救</li><li>地址填写后通常无法修改，请仔细核对后再提交</li><li>如需修改地址，请在发货前尽快联系客服</li><li>国际快递时效一般为 7-15 个工作日，国内快递一般为 3-7 个工作日</li></ul><h3 id="电子券" tabindex="-1">电子券 <a class="header-anchor" href="#电子券" aria-label="Permalink to &quot;电子券&quot;">​</a></h3><p>电子券不会自动激活，需要用户在 APP 内主动点击「激活」按钮后才能使用。电子券具有两层时效：</p><ol><li>激活截止时间：必须在此时间前完成激活，超时后电子券作废</li><li>激活后有效期：激活成功后另计有效期，从激活成功的那一刻开始计算</li></ol><p>使用步骤：</p><ol><li>进入奖品详情页，点击「激活」按钮主动激活电子券</li><li>激活通常在 1 分钟内完成，状态变为「已激活」</li><li>激活成功后，在 APP 内查看电子券二维码或码号</li><li>前往指定商户消费时，向店员出示电子券或输入码号</li></ol><p>注意事项：</p><ul><li>激活前请确认当前时间在激活截止时间之内，否则无法激活</li><li>激活后有效期从激活时刻开始计算，与获得时间无关</li><li>电子券一旦激活，不支持退回或转让</li></ul><h3 id="my-link-积分" tabindex="-1">My Link 积分 <a class="header-anchor" href="#my-link-积分" aria-label="Permalink to &quot;My Link 积分&quot;">​</a></h3><p>My Link 积分是在 My Link 平台使用的专属积分，奖品发放后会有一段锁仓期（例如 30 天），锁仓期结束后积分才正式到账并可使用。</p><p>查看步骤：</p><ol><li>在奖品详情页查看积分数量和预计到账时间（香港时间 HKT）</li><li>锁仓期内，积分显示为「锁定中」</li><li>到账后，登录 My Link 平台查看和使用积分</li></ol><p>注意事项：</p><ul><li>锁仓期间账户资产若不达标，平台有权取消该笔积分发放</li><li>请保持账户资产符合要求，确保积分顺利到账</li><li>具体锁仓期天数以奖品详情页说明为准</li><li>如积分到期仍未到账，请联系客服并提供奖品记录截图</li></ul><h3 id="卡密" tabindex="-1">卡密 <a class="header-anchor" href="#卡密" aria-label="Permalink to &quot;卡密&quot;">​</a></h3><p>领取步骤：</p><ol><li>进入奖品详情页，点击「领取卡密」按钮</li><li>系统展示密钥（包含兑换码和可能的验证码）</li><li>请立即截图或记录密钥，密钥只能查看一次</li><li>前往对应第三方平台，在兑换页面输入密钥完成兑换</li></ol><p>注意事项：</p><ul><li>卡密只能领取一次，领取后无法重新查看，请务必保存好</li><li>请勿将卡密截图分享给他人，避免被他人使用</li><li>卡密兑换规则以第三方平台为准</li><li>如卡密无法使用，请先联系第三方平台客服；确认密钥本身有误再联系客服</li></ul><h2 id="兑换、配送与取消答疑" tabindex="-1">兑换、配送与取消答疑 <a class="header-anchor" href="#兑换、配送与取消答疑" aria-label="Permalink to &quot;兑换、配送与取消答疑&quot;">​</a></h2><p><strong>Q：我获得了实物奖品，但找不到填写地址的入口怎么办？</strong></p><p>A：请在 APP「奖励中心」或活动详情页找到对应奖品，点击进入详情页即可看到「填写收货地址」按钮。如仍无法找到，请联系客服并提供活动名称和账户信息。</p><hr><p><strong>Q：填写地址后可以修改吗？</strong></p><p>A：地址提交后原则上无法自行修改。如确需更改，请在奖品状态变为「发货中」之前尽快联系客服。一旦进入发货流程，将无法更改地址。</p><hr><p><strong>Q：电子券显示「激活中」已经超过 10 分钟，还没激活成功怎么办？</strong></p><p>A：正常激活在 1 分钟内完成。若超过 10 分钟仍显示「激活中」，请尝试退出并重新进入奖品详情页刷新状态。若仍未激活，请联系客服并提供奖品截图。</p><hr><p><strong>Q：电子券已过期但我还没用，可以补发吗？</strong></p><p>A：电子券过期后一般无法补发。如过期原因是系统问题或激活失败，请联系客服说明情况，我们将核实后按实际情况处理。</p><hr><p><strong>Q：My Link 积分什么时候到账？</strong></p><p>A：积分到账时间 = 奖品发放日 + 锁仓天数，具体预计到账时间（香港时间）在奖品详情页中有显示。请以详情页展示的时间为准。</p><hr><p><strong>Q：My Link 积分锁仓期内账户资产不达标会怎样？</strong></p><p>A：若在锁仓期内账户资产持续低于要求标准，平台有权取消该笔积分的发放。建议保持账户资产在要求水平以上。</p><hr><p><strong>Q：我的卡密领取后发现已被使用或无效，怎么办？</strong></p><p>A：请先前往第三方平台客服确认密钥状态。若确认密钥在您领取时已失效或被他人使用，请联系客服，并提供领取记录截图。</p><hr><p><strong>Q：奖品显示「已退回」，我能重新收到吗？</strong></p><p>A：奖品退回通常是因为地址有误或无法送达。请联系客服说明情况，提供正确的收货地址，客服核实后会安排重新发货（以实际库存和活动规则为准）。</p><hr><p><strong>Q：我的奖品物流信息很久没更新，是不是丢件了？</strong></p><p>A：物流信息有时会有延迟。建议用物流单号在快递官网或 APP 查询最新状态。若 3 个工作日内物流无任何更新，请联系客服，提供物流单号，客服将协助联系快递公司核查。</p><hr><p><strong>Q：电子券的有效期是从什么时候开始算？</strong></p><p>A：电子券的有效期从激活成功的那一刻开始计算，而不是从获得电子券的时间开始。例如，激活后 30 天有效，则有效期截止时间 =<br> 激活成功的时间 + 30 天。请注意：激活前还有「激活截止时间」，必须在该时间前完成激活，否则电子券将作废。</p><hr><p><strong>Q：我错过填写地址的截止时间了怎么办？</strong></p><p>A：实物商品的领取截止时间一旦过期，奖品将自动失效且无法系统恢复。如有特殊原因（如系统故障、通知未收到等），请立即联系客服说明情况，但无法保证一定可以补救。建议收到奖品后尽快完成地址填写。</p><hr><p><strong>Q：My Link 积分的锁仓期是什么意思？</strong></p><p>A：锁仓期是指积分发放后暂时冻结、不可使用的一段时间。在锁仓期内，积分显示为「锁定中」，无法在 My Link<br> 平台使用。锁仓期结束后积分才正式到账并可自由使用。若在锁仓期内账户资产低于要求标准，平台有权取消该笔积分的发放。</p><hr><p><strong>Q：IPO 打新活动的卡券怎么使用？需要手动操作吗？</strong></p><p>A：不需要手动操作。系统会在您参与 IPO 申购时自动识别并使用对应卡券。请注意区分通用卡（适用所有 IPO）和指定股票卡（仅适用特定<br> IPO），在卡券详情中可以确认适用范围。</p><hr><p><strong>Q：IPO 延期了，我的打新卡有效期会怎样？</strong></p><p>A：若 IPO 延期，对应卡券的有效期也会随之延长，与 IPO 新的结束时间保持一致。</p><h2 id="配送限制与退换规则" tabindex="-1">配送限制与退换规则 <a class="header-anchor" href="#配送限制与退换规则" aria-label="Permalink to &quot;配送限制与退换规则&quot;">​</a></h2><ul><li>地址填写时限：实物商品设有领取截止时间，超过截止时间未填写地址，奖品将自动失效且无法补救</li><li>电子券双层时效：电子券有「激活截止时间」和「激活后有效期」两层限制，激活后有效期从激活成功时刻开始计算</li><li>卡密只能领取一次，电子券通常不支持退换，请在操作前确认</li><li>所有时间（到账时间、过期时间等）均为香港时间（HKT，UTC+8）</li><li>遇到任何问题，请通过 APP 内「联系客服」功能提交，附上奖品截图可加快处理速度</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/rewards">活动与奖励</a></li></ul>',78)])])}const P=l(d,[["render",e]]);export{c as __pageData,P as default};
